import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import "./css/ProductList.css";

const ProductList = () => {
  const [products, setProducts] = useState([]);
  const scrollRef = useRef(null);

  useEffect(() => {
    // Fetch products when the component mounts
    axios
      .get("http://localhost:3000/api/v1/products")
      .then((response) => {
        setProducts(response.data);
      })
      .catch((error) => {
        console.error("There was an error fetching the products!", error);
      });
  }, []);

  // Scroll functions
  const scrollLeft = () => {
    scrollRef.current.scrollBy({ left: -400, behavior: "smooth" });
  };

  const scrollRight = () => {
    scrollRef.current.scrollBy({ left: 400, behavior: "smooth" });
  };

  return (
    <div id="root">
      {/* Rare Finds Section */}
      <section
        id="rare_finds"
        className="py-20 bg-gradient-to-b from-black to-zinc-900 text-white"
      >
        <div className="container mx-auto px-4">
          {/* Section Header */}
          <div className="text-center max-w-3xl mx-auto mb-16">
            <span className="text-red-500 font-semibold mb-2 block">
              Limited Availability
            </span>
            <h2 className="text-4xl md:text-5xl font-bold mb-4">Rare Finds</h2>
            <p className="text-gray-400 text-lg">
              Discover our most exclusive and sought-after collector's items
            </p>
          </div>

          {/* Featured Rare Item */}
          <div className="grid md:grid-cols-2 gap-12 mb-20">
            <div className="relative group">
              <div className="aspect-square rounded-2xl bg-gradient-to-br from-red-500/10 to-purple-500/10 flex items-center justify-center overflow-hidden">
                <i className="fa-solid fa-car text-8xl text-red-500 group-hover:scale-110 transition-transform duration-500"></i>
                <div className="absolute top-4 left-4 bg-red-500 text-white px-4 py-1 rounded-full text-sm">
                  Only 5 Left
                </div>
              </div>
            </div>
            <div className="flex flex-col justify-center">
              <h3 className="text-3xl font-bold mb-4">1967 Custom Mustang</h3>
              <p className="text-gray-400 mb-6">
                Limited edition gold-plated collector's series with authentic
                details and premium packaging.
              </p>
              <div className="space-y-4 mb-8">
                <div className="flex items-center gap-4">
                  <i className="fa-solid fa-medal text-red-500"></i>
                  <span>Numbered Collection</span>
                </div>
                <div className="flex items-center gap-4">
                  <i className="fa-solid fa-certificate text-red-500"></i>
                  <span>Authentication Certificate</span>
                </div>
                <div className="flex items-center gap-4">
                  <i className="fa-solid fa-box text-red-500"></i>
                  <span>Premium Display Case</span>
                </div>
              </div>
              <div className="flex items-center gap-6 mb-8">
                <div className="text-3xl font-bold">$199.99</div>
                <div className="text-lg text-gray-400 line-through">
                  $249.99
                </div>
              </div>
              <div className="flex gap-4">
                <button className="flex-1 bg-red-500 hover:bg-red-600 py-3 rounded-full transition-colors">
                  Reserve Now
                </button>
                <button className="w-12 h-12 rounded-full border border-white/20 hover:border-white/40 flex items-center justify-center">
                  <i className="fa-regular fa-heart"></i>
                </button>
              </div>
            </div>
          </div>

          {/* Other Rare Finds */}
          <div className="grid md:grid-cols-3 gap-6">
            {/* Map over Rare Finds (Example Items) */}
            {[
              {
                title: "Vintage Racer Pro",
                price: "$149.99",
                description: "Special edition chrome finish",
                iconClass: "fa-car-side",
                iconColor: "text-blue-500",
                gradient: "from-blue-500/10 to-blue-900/10",
                detailsColor: "text-blue-500 hover:text-blue-400",
              },
              {
                title: "Classic GT 500",
                price: "$179.99",
                description: "Collector's edition with display",
                iconClass: "fa-car",
                iconColor: "text-purple-500",
                gradient: "from-purple-500/10 to-purple-900/10",
                detailsColor: "text-purple-500 hover:text-purple-400",
              },
              {
                title: "Modern Supercar",
                price: "$129.99",
                description: "Limited production run",
                iconClass: "fa-car-rear",
                iconColor: "text-green-500",
                gradient: "from-green-500/10 to-green-900/10",
                detailsColor: "text-green-500 hover:text-green-400",
              },
            ].map((item, index) => (
              <div
                key={index}
                className={`bg-zinc-800 rounded-2xl p-6 group hover:bg-zinc-700 transition-colors`}
              >
                <div
                  className={`aspect-square rounded-xl bg-gradient-to-br ${item.gradient} flex items-center justify-center mb-6`}
                >
                  <i
                    className={`fa-solid ${item.iconClass} text-5xl ${item.iconColor} group-hover:scale-110 transition-transform`}
                  ></i>
                </div>
                <h4 className="text-xl font-bold mb-2">{item.title}</h4>
                <p className="text-gray-400 mb-4">{item.description}</p>
                <div className="flex justify-between items-center">
                  <span className="text-xl font-bold">{item.price}</span>
                  <button className={`${item.detailsColor} transition-colors`}>
                    View Details
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
      {/* Continue with other sections... */}
    </div>
  );
};

export default ProductList;
